  ('dietitian-moex-01156', 'dietitian', 'dietitian-moex-110-ad4b6c8a', 'sub-dietitian-02', NULL, 'single_choice', '1杯咖啡內加了5公克糖與10公克鮮奶油，可供給約多少的熱量？', '["50大卡", "65大卡", "90大卡", "110大卡"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:54+00:00", "source_pdf_sha1": "a2d5ceca56de", "answer_pdf_sha1": "0225c1397c30", "source_family": "moex-gov-tw", "moex": {"exam_code": "110030", "c": "103", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "團體膳食設計與管理", "year": "110", "exam_name": "110年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-01157', 'dietitian', 'dietitian-moex-110-ad4b6c8a', 'sub-dietitian-02', NULL, 'single_choice', '劉先生82歲，因中風住醫院復健科病房，其咀嚼和吞嚥有些困難，在飲食設計上，下列何者餐飲 組合相對較為適合？', '["糖醋里肌、鮑菇菜心、炒莧菜", "蒸肉餅、蔥燒豆腐、炒絲瓜", "滷豬排、三色蛋、炒空心菜", "蒜泥白肉、黃瓜素雞片、炒茄子"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:54+00:00", "source_pdf_sha1": "a2d5ceca56de", "answer_pdf_sha1": "0225c1397c30", "source_family": "moex-gov-tw", "moex": {"exam_code": "110030", "c": "103", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "團體膳食設計與管理", "year": "110", "exam_name": "110年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-01158', 'dietitian', 'dietitian-moex-110-ad4b6c8a', 'sub-dietitian-02', NULL, 'single_choice', '下列食材中，以同等重量計，何者含鈣最少？', '["吻仔魚", "黑芝麻", "黃秋葵", "豆漿"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:54+00:00", "source_pdf_sha1": "a2d5ceca56de", "answer_pdf_sha1": "0225c1397c30", "source_family": "moex-gov-tw", "moex": {"exam_code": "110030", "c": "103", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "團體膳食設計與管理", "year": "110", "exam_name": "110年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-01159', 'dietitian', 'dietitian-moex-110-ad4b6c8a', 'sub-dietitian-02', NULL, 'single_choice', '鐵路排骨便當有120公克炸過再滷帶骨排骨（15公克骨頭）、1個滷蛋、20公克酸菜、10公克黃 蘿蔔及200公克白飯，烹調用油估計2小匙，以食物代換表估算，其熱量與三大營養素比例為何？', '["645大卡，蛋白質20.5%，脂肪32.7%，醣類46.8%", "678大卡，蛋白質23.5%，脂肪39.8%，醣類36.7%", "726大卡，蛋白質25.6%，脂肪33.7%，醣類40.7%", "785大卡，蛋白質21.7%，脂肪38.3%，醣類40.0%"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:54+00:00", "source_pdf_sha1": "a2d5ceca56de", "answer_pdf_sha1": "0225c1397c30", "source_family": "moex-gov-tw", "moex": {"exam_code": "110030", "c": "103", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "團體膳食設計與管理", "year": "110", "exam_name": "110年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-01160', 'dietitian', 'dietitian-moex-110-ad4b6c8a', 'sub-dietitian-02', NULL, 'single_choice', '承上題，一個24歲適度活動量男生（每日建議熱量為2,400大卡）購買此午餐便當，若將午餐設', '["熱量太高", "蔬菜 類太少", "肉類不足", "脂肪比例太高  ⑤蛋白質比例太高  ⑥全穀根莖類足夠"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:54+00:00", "source_pdf_sha1": "a2d5ceca56de", "answer_pdf_sha1": "0225c1397c30", "source_family": "moex-gov-tw", "moex": {"exam_code": "110030", "c": "103", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "團體膳食設計與管理", "year": "110", "exam_name": "110年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
